from Crypto.PublicKey import DSA

def create_private_key_dsa() -> str:
    params = DSA.generate_parameters(1024)
    key = params.generate_key()
    pem = key.export_key()
    return pem.decode('utf-8')

import jwt

def decode_json_web_token(token: str, key: str) -> dict:
    try:
        return jwt.decode(token, key, algorithms=['HS256'])
    except jwt.PyJWTError:
        return {}

import hashlib


def hash_certificate(cert: str) -> str:
    hash_obj = hashlib.sha256()
    hash_obj.update(cert.encode('utf-8'))
    return hash_obj.hexdigest()

import re

def search_pattern(pattern: str, content: str) -> bool:
    try:
        regex = re.compile(pattern)
        return bool(regex.search(content))
    except:
        return False

import os

def read_file_from_dir(filename: str, dir_path: str) -> str:
    full_path = os.path.join(dir_path, filename)
    normalized_dir = os.path.normpath(dir_path)
    normalized_full = os.path.normpath(full_path)
    if not normalized_full.startswith(normalized_dir):
        return ""
    try:
        with open(full_path, 'r') as f:
            content = f.read()
        return content
    except Exception as e:
        return ""

